namespace sv_a2e9b5fb854a4f1ab2c3f18b7a573075.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_a2e9b5fb854a4f1ab2c3f18b7a573075.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Margherita Pizza", "Classic Italian pizza with fresh mozzarella, basil, and tomato sauce.", 30),
            new(2, "Spaghetti Carbonara", "Creamy pasta with pancetta, egg yolk, and pecorino romano.", 25),
            new(3, "Tiramisu", "Layered coffee-flavored dessert with mascarpone cream.", 45),
        },
        [2] = new List<Recipe>
        {
            new(4, "Chicken Tikka Masala", "Tender chicken in a rich, spiced tomato-cream sauce.", 50),
            new(5, "Palak Paneer", "Fresh spinach cooked with paneer cubes and aromatic spices.", 35),
            new(6, "Biryani", "Fragrant basmati rice layered with spiced meat and caramelized onions.", 60),
        },
        [3] = new List<Recipe>
        {
            new(7, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 40),
            new(8, "Guacamole", "Fresh avocado dip with lime, cilantro, and jalapeño.", 10),
            new(9, "Enchiladas Verdes", "Corn tortillas filled with chicken and topped with green salsa.", 35),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_a2e9b5fb854a4f1ab2c3f18b7a573075.Services
@implements IDisposable
@inject IRecipeService RecipeService
@inject NavigationManager Navigation
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes...</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;
    private readonly CancellationTokenSource _disposeCts = new();

    private IEnumerable<Recipe> DisplayedRecipes =>
        string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
            ? _recipes!.OrderByDescending(r => r.Id)
            : string.Equals(Sort, "newest", StringComparison.OrdinalIgnoreCase)
                ? _recipes!.OrderByDescending(r => r.PrepTimeMinutes)
                : _recipes!;

    protected override Task OnParametersSetAsync()
    {
        if (CuisineId != _loadedCuisineId)
        {
            return LoadRecipesAsync();
        }

        return Task.CompletedTask;
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;
        _loadedCuisineId = CuisineId;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);
            _recipes = results;
            _isRefreshing = false;
        }
        catch (OperationCanceledException) when (token.IsCancellationRequested)
        {
            // Request was cancelled (navigation or new cuisine) — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
            _isRefreshing = false;
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
            _isRefreshing = false;
        }
    }

    private Task RetryAsync() => LoadRecipesAsync();

    public void Dispose()
    {
        _disposeCts.Cancel();
        _disposeCts.Dispose();
        _cts?.Dispose();
    }
}

